class.brief_description:
Test helper that intercepts [method C3Http.request] calls. Install with [method C3Http.Mock.install], configure canned responses with [method C3Http.Mock.stub], and inspect recorded calls via [member C3Http.Mock.calls]. Always pair [method C3Http.Mock.install] with [method C3Http.Mock.uninstall] in [code]after_each()[/code].
[codeblock] var mock: C3Http.Mock
func before_each() -> void: mock = C3Http.Mock.new() mock.install()
func after_each() -> void: mock.uninstall()
func test_example() -> void: mock.stub().ok({"id": 1}) var res := await C3Http.request("https://api.example.com/users") assert_true(res.ok) assert_eq(mock.last_call["url"], "https://api.example.com/users") [/codeblock]
